CREATE OR REPLACE PROCEDURE
    sp_login_user(
        provided_email VARCHAR(30),
        provided_password VARCHAR(15)
)
AS
$$
DECLARE
    credentials_not_correct CONSTANT TEXT :=
        'The email or password you entered is incorrect. ' ||
        'Please check your email and password, and try again.';

    hashed_password VARCHAR(100);

    user_id INTEGER;
BEGIN
    hashed_password := ENCODE(
        DIGEST(
            provided_password, 'sha256'
            ), 'hex'
        );

    user_id := (
            SELECT
                id
            FROM
                customer_users
            WHERE
                email= provided_email
                        AND
                password = hashed_password
        );

    IF
        user_id IS NULL
    THEN
        SELECT fn_raise_error_message(credentials_not_correct);

    ELSE
        CALL sp_generate_session_token(
                user_id
        );
    END IF;
END;
$$
LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION awa.sync_job_admin_metadata() RETURNS trigger AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        PERFORM awa.apply_queue_state_delta(NEW.queue, NEW.state, 1);
        PERFORM awa.apply_job_kind_delta(NEW.kind, 1);
        PERFORM awa.apply_job_queue_delta(NEW.queue, 1);
        RETURN NEW;
    END IF;

    IF TG_OP = 'DELETE' THEN
        PERFORM awa.apply_queue_state_delta(OLD.queue, OLD.state, -1);
        PERFORM awa.apply_job_kind_delta(OLD.kind, -1);
        PERFORM awa.apply_job_queue_delta(OLD.queue, -1);
        RETURN OLD;
    END IF;

    IF OLD.queue IS DISTINCT FROM NEW.queue OR OLD.state IS DISTINCT FROM NEW.state THEN
        PERFORM awa.apply_queue_state_delta(OLD.queue, OLD.state, -1);
        PERFORM awa.apply_queue_state_delta(NEW.queue, NEW.state, 1);
    END IF;

    IF OLD.kind IS DISTINCT FROM NEW.kind THEN
        PERFORM awa.apply_job_kind_delta(OLD.kind, -1);
        PERFORM awa.apply_job_kind_delta(NEW.kind, 1);
    END IF;

    IF OLD.queue IS DISTINCT FROM NEW.queue THEN
        PERFORM awa.apply_job_queue_delta(OLD.queue, -1);
        PERFORM awa.apply_job_queue_delta(NEW.queue, 1);
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql

create or replace function app.update_avatar_id()
    returns trigger
    language plpgsql
    security definer
    as $$
    declare
        v_handle app.valid_name;
        v_affected_account app.accounts := null;
    begin
        select (string_to_array(new.name, '/'::text))[1]::app.valid_name into v_handle;

        update app.accounts
        set avatar_id = new.id
        where handle = v_handle
        returning * into v_affected_account;

        if not v_affected_account is null then
            update auth.users u
            set
                "raw_user_meta_data" = u.raw_user_meta_data || jsonb_build_object(
                    'avatar_path', new.name
                )
            where u.id = v_affected_account.id;
        else
            update app.organizations
            set avatar_id = new.id
            where handle = v_handle;
        end if;

        return new;
    end;
    $$

CREATE OR REPLACE FUNCTION zitadel.ensure_user_verification_integrity() RETURNS trigger AS $$
BEGIN
    IF (NEW.password_verification_id IS DISTINCT FROM OLD.password_verification_id) THEN
        DELETE FROM zitadel.verifications
        WHERE instance_id = NEW.instance_id
        AND id = OLD.password_verification_id;
    END IF;

    IF (NEW.email_verification_id IS DISTINCT FROM OLD.email_verification_id) THEN
        DELETE FROM zitadel.verifications
        WHERE instance_id = NEW.instance_id
        AND id = OLD.email_verification_id;
    END IF;

    IF (NEW.phone_verification_id IS DISTINCT FROM OLD.phone_verification_id) THEN
        DELETE FROM zitadel.verifications
        WHERE instance_id = NEW.instance_id
        AND id = OLD.phone_verification_id;
    END IF;

    IF (NEW.invite_verification_id IS DISTINCT FROM OLD.invite_verification_id) THEN
        DELETE FROM zitadel.verifications
        WHERE instance_id = NEW.instance_id
        AND id = OLD.invite_verification_id;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql

create table secured_table(
    id uuid primary key default uuid_generate_v4(),
    created_at timestamp with time zone default now(),
    organization_id text not null
);

alter table secured_table
enable row level security;

create policy "Only organization admins can insert in table"
on secured_table
for insert
to authenticated
with check (
  (((select auth.jwt()->>'org_role') = 'org:admin') or ((select auth.jwt()->'o'->>'rol') = 'admin'))
    and
  (organization_id = (select coalesce(auth.jwt()->>'org_id', auth.jwt()->'o'->>'id')))
);

create policy "Users can select from their own organization"
on secured_table
for select
to authenticated
using (
  (organization_id = (select coalesce(auth.jwt()->>'org_id', auth.jwt()->'o'->>'id')))
);

create policy "Only users that have passed second factor verification can read from table"
on secured_table
as restrictive
for select
to authenticated
using (
  ((select auth.jwt()->'fva'->>1) != '-1')
);

CREATE OR REPLACE FUNCTION pgmq.validate_routing_key(routing_key text)
    RETURNS boolean
    LANGUAGE plpgsql
    IMMUTABLE
AS
$$
BEGIN
    IF routing_key IS NULL OR routing_key = '' THEN
        RAISE EXCEPTION 'routing_key cannot be NULL or empty';
    END IF;

    IF length(routing_key) > 255 THEN
        RAISE EXCEPTION 'routing_key length cannot exceed 255 characters, got % characters', length(routing_key);
    END IF;

    IF routing_key !~ '^[a-zA-Z0-9._-]+$' THEN
        RAISE EXCEPTION 'routing_key contains invalid characters. Only alphanumeric, dots, hyphens, and underscores are allowed. Got: %', routing_key;
    END IF;

    IF routing_key ~ '^\.' THEN
        RAISE EXCEPTION 'routing_key cannot start with a dot. Got: %', routing_key;
    END IF;

    IF routing_key ~ '\.$' THEN
        RAISE EXCEPTION 'routing_key cannot end with a dot. Got: %', routing_key;
    END IF;

    IF routing_key ~ '\.\.' THEN
        RAISE EXCEPTION 'routing_key cannot contain consecutive dots. Got: %', routing_key;
    END IF;

    RETURN true;
END;
$$;

CREATE OR REPLACE FUNCTION @extschema@.hypertable_detailed_size(hypertable REGCLASS)
RETURNS TABLE (table_bytes BIGINT, index_bytes BIGINT,
               toast_bytes BIGINT, total_bytes BIGINT, node_name NAME)
LANGUAGE PLPGSQL VOLATILE STRICT AS
$BODY$
DECLARE
    table_name  NAME = NULL;
    schema_name NAME = NULL;
BEGIN
    SELECT relname, nspname INTO table_name, schema_name
    FROM pg_class c
    INNER JOIN pg_namespace n ON (n.OID = c.relnamespace)
    INNER JOIN _timescaledb_catalog.hypertable ht ON (ht.schema_name = n.nspname AND ht.table_name = c.relname)
    WHERE c.OID = hypertable;

    IF table_name IS NULL THEN
        SELECT h.schema_name, h.table_name INTO schema_name, table_name
        FROM pg_class c
        INNER JOIN pg_namespace n ON (n.OID = c.relnamespace)
        INNER JOIN _timescaledb_catalog.continuous_agg a ON (a.user_view_schema = n.nspname AND a.user_view_name = c.relname)
        INNER JOIN _timescaledb_catalog.hypertable h ON h.id = a.mat_hypertable_id
        WHERE c.OID = hypertable;

        IF table_name IS NULL THEN
            RETURN;
        END IF;
    END IF;

    RETURN QUERY
    SELECT *, NULL::name
    FROM _timescaledb_functions.hypertable_local_size(schema_name, table_name);
END;
$BODY$ SET search_path TO pg_catalog, pg_temp;

create or replace function row_exists(in row_id row_id, out answer boolean) as $$
    declare
        stmt text;
        pk_comparisons text[];
        pk_comparison_stmt text;
        column_name text;
        i integer;
    begin
        -- generate the pk comparisons line
        i := 1;
        foreach column_name in array row_id.pk_column_names loop
            pk_comparisons[i] := quote_ident((row_id).pk_column_names[i]) || '::text = ' || quote_literal((row_id).pk_values[i]);
            i := i + 1;
        end loop;
        pk_comparison_stmt := array_to_string(pk_comparisons, ' and ');


        stmt := format (
            -- 'select (count(*) = 1) from %I.%I where %I::text = %L',
            'select (count(*) = 1) from %I.%I where %s',
                (row_id).schema_name,
                (row_id).relation_name,
                pk_comparison_stmt
            );

        raise debug '%', stmt;
        execute stmt into answer;

    exception
        when undefined_table then
            answer := false;
    end;
$$ language plpgsql

create function sum_type_provision_trigger() returns trigger
    language plpgsql
as
$$
begin
    -- Hash?
    perform from pg_proc where proname = new.typ || '_hash' and pronamespace = current_schema()::regnamespace;

    if found then
        execute format('create operator family %I using hash', new.typ || '_hash_ops');

        execute format('create operator class %I
        default for type %2$I using hash
        family %3$I as
        operator 1 =,
        function 1 %4$I(%2$I)', new.typ || '_hash_ops_class', new.typ, new.typ || '_hash_ops', new.typ || '_hash');
    end if;

    -- Btree?
    perform from pg_proc where proname = new.typ || '_cmp' and pronamespace = current_schema()::regnamespace;

    if found then
        execute format('create operator family %I using btree', new.typ || '_btree_ops');

        execute format('create operator class %I
        default for type %2$I using btree
        family %3$I as
        operator 1 <,
        operator 2 <=,
        operator 3 =,
        operator 4 >=,
        operator 5 >,
        function 1 %4$I(%2$I,%2$I)', new.typ || '_btree_ops_class', new.typ, new.typ || '_btree_ops',
                       new.typ || '_cmp');
    end if;

    return new;
end;
$$

create or replace function explain_analyze_inc_sort_nodes(query text)
returns jsonb language plpgsql
as
$$
declare
  elements jsonb;
  element jsonb;
  matching_nodes jsonb := '[]'::jsonb;
begin
  execute 'explain (analyze, costs off, summary off, timing off, buffers off, format ''json'') ' || query into strict elements;
  while jsonb_array_length(elements) > 0 loop
    element := elements->0;
    elements := elements - 0;
    case jsonb_typeof(element)
    when 'array' then
      if jsonb_array_length(element) > 0 then
        elements := elements || element;
      end if;
    when 'object' then
      if element ? 'Plan' then
        elements := elements || jsonb_build_array(element->'Plan');
        element := element - 'Plan';
      else
        if element ? 'Plans' then
          elements := elements || jsonb_build_array(element->'Plans');
          element := element - 'Plans';
        end if;
        if (element->>'Node Type')::text = 'Incremental Sort' then
          matching_nodes := matching_nodes || element;
        end if;
      end if;
    end case;
  end loop;
  return matching_nodes;
end;
$$

CREATE OR REPLACE FUNCTION _timescaledb_functions.policy_job_stat_history_retention_check(config JSONB) RETURNS VOID
LANGUAGE PLPGSQL AS
$BODY$
BEGIN
    IF config IS NULL THEN
        RAISE EXCEPTION 'config cannot be NULL, and must contain drop_after';
    END IF;

    IF NOT (config ? 'drop_after') THEN
        RAISE EXCEPTION 'drop_after interval not provided';
    END IF;

    IF NOT (config ? 'max_successes_per_job') THEN
        RAISE EXCEPTION 'max_successes_per_job not provided';
    END IF;

    IF NOT (config ? 'max_failures_per_job') THEN
        RAISE EXCEPTION 'max_failures_per_job not provided';
    END IF;

    IF (config->>'max_successes_per_job')::integer < 10 THEN
        RAISE EXCEPTION 'max_successes_per_job has to be at least 10';
    END IF;

    IF (config->>'max_failures_per_job')::integer < 10 THEN
        RAISE EXCEPTION 'max_failures_per_job has to be at least 10';
    END IF;
END
$BODY$ SET search_path TO pg_catalog, pg_temp

-- Remove chunk metadata when marked as dropped
CREATE OR REPLACE FUNCTION _timescaledb_functions.remove_dropped_chunk_metadata(_hypertable_id INTEGER)
RETURNS INTEGER LANGUAGE plpgsql AS $$
DECLARE
  _chunk_id INTEGER;
  _removed INTEGER := 0;
BEGIN
  FOR _chunk_id IN
    SELECT id FROM _timescaledb_catalog.chunk
    WHERE hypertable_id = _hypertable_id
    AND NOT EXISTS (
        SELECT FROM information_schema.tables
        WHERE tables.table_schema = chunk.schema_name
        AND tables.table_name = chunk.table_name
    )
  LOOP
    _removed := _removed + 1;
    RAISE INFO 'Removing metadata of chunk % from hypertable %', _chunk_id, _hypertable_id;

    DELETE FROM _timescaledb_catalog.dimension_slice
    WHERE chunk_id = _chunk_id;

    DELETE FROM _timescaledb_internal.bgw_policy_chunk_stats
    WHERE bgw_policy_chunk_stats.chunk_id = _chunk_id;

    DELETE FROM _timescaledb_catalog.compression_chunk_size
    WHERE compression_chunk_size.chunk_id = _chunk_id
    OR compression_chunk_size.compressed_chunk_id = _chunk_id;

    DELETE FROM _timescaledb_catalog.chunk
    WHERE chunk.id = _chunk_id
    OR chunk.compressed_chunk_id = _chunk_id;
  END LOOP;

  RETURN _removed;
END;
$$ SET search_path TO pg_catalog, pg_temp

CREATE OR REPLACE FUNCTION _timescaledb_functions.jsonb_get_matching_index_entry(
    config jsonb,
    attr_name text,
    target_type text
) RETURNS jsonb AS $$
DECLARE
    elem jsonb;
    attr_count int := 0;
BEGIN
  -- Return NULL if any input is NULL
  IF config IS NULL OR attr_name IS NULL OR target_type IS NULL THEN
    RETURN NULL;
  END IF;

  FOR elem IN SELECT * FROM jsonb_array_elements(config)
  LOOP
    IF elem->>'column' =  attr_name THEN
      attr_count := attr_count + 1;

      IF elem->>'type' = target_type THEN
        IF attr_count > 2 THEN
          RAISE EXCEPTION 'Found % sparse index entries for attribute "%"', attr_count, attr_name;
        END IF;
        RETURN elem;
      END IF;
    END IF;
  END LOOP;

  IF attr_count > 2 THEN
    RAISE EXCEPTION 'Found % sparse index entries for attribute "%"', attr_count, attr_name;
  END IF;

  RETURN NULL;
END;
$$ LANGUAGE PLPGSQL
